SELECT movie."name", movie.cover, re_release.movie_id, re_release."id", re_release.start_date, re_release.end_date, re_release.status, re_release.version_info, re_release.display_name_override, re_release.poster_override, re_release.time_override FROM re_release LEFT JOIN movie ON re_release.movie_id = movie.id
re_release.deleted = 0
AND movie.id = #{query.movieId}
AND movie.id = #{query.id}
AND movie.name LIKE concat('%', #{query.name}, '%')
AND movie.status = #{query.status}
